/* ═══════════════════════════════════════════════════════════════════════════
   GRAMMAR DATA — N5 level, didactic, organized by topic
   ═══════════════════════════════════════════════════════════════════════════ */


/* ═══════════════════════════════════════════════════════════════════════════
   AUTH SYSTEM
   - Users stored in shared storage: "db_user:{username}" → UserRecord
   - Session stored locally: "session" → {username, token}
   - Simple SHA-like hash for passwords (client-side, educational app)
   ═══════════════════════════════════════════════════════════════════════════ */

// Simple deterministic hash (not cryptographic — fine for an educational app)
function hashPassword(password, salt) {
  let h = 0;
  const str = password + salt + "hira_studio_2025";
  for (let i = 0; i < str.length; i++) {
    h = ((h << 5) - h) + str.charCodeAt(i);
    h |= 0;
  }
  return Math.abs(h).toString(36) + str.length.toString(36);
}

function generateToken() {
  return Math.random().toString(36).slice(2) + Date.now().toString(36);
}

// ── JLPT Level Calculator ─────────────────────────────────────────────────
function calcJLPT(srsData, learnedLessons, reviewHistory) {
  const cards = Object.values(srsData);
  const mastered    = cards.filter(c => c.state === "review" && c.interval >= 21).length;
  const inReview    = cards.filter(c => c.state === "review").length;
  const seen        = Object.keys(srsData).length;
  const totalReviews= Object.values(reviewHistory).reduce((s,v) => s + v.seen, 0);
  const correctAll  = Object.values(reviewHistory).reduce((s,v) => s + v.correct, 0);
  const retention   = totalReviews > 0 ? (correctAll / totalReviews) * 100 : 0;
  const grammarDone = Object.values(learnedLessons).filter(Boolean).length;

  // N5 requirement: all kana (92 cards), basic grammar (9 lessons), decent retention
  const kanaComplete = seen >= 80;
  const grammarBase  = grammarDone >= 6;
  const masteredGood = mastered >= 40;

  // Score 0-100 for each level requirement
  const n5Score = Math.min(100, Math.round(
    (Math.min(seen, 92) / 92) * 40 +
    (Math.min(grammarDone, 9) / 9) * 30 +
    (Math.min(mastered, 50) / 50) * 20 +
    (retention >= 70 ? 10 : retention / 7)
  ));

  // Levels beyond N5 need vocabulary (not in app yet) — show as locked with progress
  const level =
    n5Score >= 90 ? "N5" :
    n5Score >= 60 ? "Próximo N5" :
    n5Score >= 30 ? "Iniciante" :
    "Começando";

  const badge =
    n5Score >= 90 ? { l:"N5", emoji:"🏅", color:"#5BAD5E", next:"N4" } :
    n5Score >= 60 ? { l:"N5⁻", emoji:"📗", color:"#3A8FD9", next:"N5" } :
    n5Score >= 30 ? { l:"基礎", emoji:"📘", color:"#E8853A", next:"N5" } :
                   { l:"入門", emoji:"🌱", color:"#7B5CD9", next:"N5" };

  return { n5Score, level, badge, seen, mastered, inReview, retention, grammarDone, totalReviews };
}

// ── AUTH STORAGE HELPERS ──────────────────────────────────────────────────
async function dbGetUser(username) {
  try {
    const r = await window.storage.get("db_user:" + username.toLowerCase(), true);
    return r?.value ? JSON.parse(r.value) : null;
  } catch { return null; }
}

async function dbSaveUser(user) {
  try {
    await window.storage.set("db_user:" + user.username.toLowerCase(), JSON.stringify(user), true);
    return true;
  } catch { return false; }
}

async function dbGetSession() {
  try {
    const r = await window.storage.get("hira_session");
    return r?.value ? JSON.parse(r.value) : null;
  } catch { return null; }
}

async function dbSaveSession(session) {
  try {
    await window.storage.set("hira_session", JSON.stringify(session));
  } catch {}
}

async function dbClearSession() {
  try { await window.storage.delete("hira_session"); } catch {}
}

// ── LOGIN SCREEN ──────────────────────────────────────────────────────────
const AuthScreen = memo(function AuthScreen({ onLogin }) {
  const [mode, setMode] = useState("login"); // "login" | "register"
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [displayName, setDisplayName] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [phase, setPhase] = useState(0);

  useEffect(() => {
    const t = [setTimeout(()=>setPhase(1),300), setTimeout(()=>setPhase(2),800)];
    return () => t.forEach(clearTimeout);
  }, []);

  const handleLogin = async () => {
    if (!username.trim() || !password) { setError("Preencha todos os campos."); return; }
    setLoading(true); setError("");
    const user = await dbGetUser(username.trim());
    if (!user) { setError("Usuário não encontrado."); setLoading(false); return; }
    const hash = hashPassword(password, user.salt);
    if (hash !== user.passwordHash) { setError("Senha incorreta."); setLoading(false); return; }
    const session = { username: user.username, token: generateToken(), loginAt: Date.now() };
    await dbSaveSession(session);
    onLogin(user, session);
    setLoading(false);
  };

  const handleRegister = async () => {
    if (!username.trim() || !password || !displayName.trim()) { setError("Preencha todos os campos."); return; }
    if (username.trim().length < 3) { setError("Usuário precisa ter pelo menos 3 caracteres."); return; }
    if (password.length < 6) { setError("Senha precisa ter pelo menos 6 caracteres."); return; }
    setLoading(true); setError("");
    const existing = await dbGetUser(username.trim());
    if (existing) { setError("Este usuário já existe."); setLoading(false); return; }
    const salt = generateToken();
    const user = {
      username: username.trim().toLowerCase(),
      displayName: displayName.trim(),
      passwordHash: hashPassword(password, salt),
      salt,
      photo: null,
      bio: "",
      createdAt: Date.now(),
    };
    await dbSaveUser(user);
    const session = { username: user.username, token: generateToken(), loginAt: Date.now() };
    await dbSaveSession(session);
    onLogin(user, session);
    setLoading(false);
  };

  const tr = (show, extra={}) => ({ transition:"all .5s ease", opacity:show?1:0, ...extra });

  return (
    <div style={{
      minHeight:"100vh", display:"flex", flexDirection:"column",
      alignItems:"center", justifyContent:"center",
      background:"linear-gradient(135deg, #1a0a0a 0%, #2D1515 40%, #1a0014 100%)",
      padding:24, position:"relative", overflow:"hidden",
    }}>
      {/* Background decoration */}
      <div style={{position:"absolute",inset:0,overflow:"hidden",pointerEvents:"none"}}>
        {["あ","い","う","え","お","か","き","く","け","こ"].map((c,i)=>(
          <div key={i} style={{
            position:"absolute", fontFamily:"'Noto Sans JP',sans-serif",
            fontSize:`${4+i*0.8}rem`, fontWeight:900,
            color:`rgba(217,79,59,${0.03+i*0.005})`,
            top:`${(i*17+10)%90}%`, left:`${(i*23+5)%90}%`,
            transform:`rotate(${i*15-30}deg)`, lineHeight:1,
          }}>{c}</div>
        ))}
      </div>

      {/* Logo */}
      <div style={{...tr(phase>=1,{transform:phase>=1?"scale(1) translateY(0)":"scale(0.5) translateY(20px)"}),textAlign:"center",marginBottom:28}}>
        <div style={{fontFamily:"'Noto Sans JP',sans-serif",fontSize:"5rem",fontWeight:900,color:"#D94F3B",lineHeight:1,textShadow:"0 4px 24px rgba(217,79,59,.4)"}}>ひ</div>
        <div style={{fontSize:"1.6rem",fontWeight:800,color:"#fff",letterSpacing:"-.5px",marginTop:4}}>Studio</div>
        <div style={{fontSize:".8rem",color:"rgba(255,255,255,.5)",marginTop:4}}>Aprenda Japonês do zero</div>
      </div>

      {/* Card */}
      <div style={{...tr(phase>=2,{transform:phase>=2?"translateY(0)":"translateY(20px)"}),
        background:"rgba(255,255,255,.06)",backdropFilter:"blur(16px)",
        borderRadius:24,padding:"28px 24px",width:"100%",maxWidth:380,
        border:"1px solid rgba(255,255,255,.1)",
        boxShadow:"0 24px 64px rgba(0,0,0,.5)",
      }}>
        {/* Mode tabs */}
        <div style={{display:"flex",background:"rgba(255,255,255,.06)",borderRadius:12,padding:3,marginBottom:22}}>
          {[["login","Entrar"],["register","Criar conta"]].map(([m,l])=>(
            <button key={m} onClick={()=>{setMode(m);setError("");}}
              style={{flex:1,padding:"9px",borderRadius:10,border:"none",fontFamily:"inherit",fontWeight:700,
                fontSize:".82rem",cursor:"pointer",transition:"all .2s",
                background:mode===m?"#D94F3B":"transparent",
                color:mode===m?"#fff":"rgba(255,255,255,.5)",
                boxShadow:mode===m?"0 2px 10px rgba(217,79,59,.4)":"none",
              }}>{l}</button>
          ))}
        </div>

        {/* Fields */}
        {mode==="register" && (
          <div style={{marginBottom:14}}>
            <label style={{fontSize:".74rem",fontWeight:600,color:"rgba(255,255,255,.6)",display:"block",marginBottom:5}}>Nome de exibição</label>
            <input value={displayName} onChange={e=>setDisplayName(e.target.value)}
              placeholder="Ex: Tanaka João"
              style={{...inputStyle}} onKeyDown={e=>e.key==="Enter"&&handleRegister()}/>
          </div>
        )}
        <div style={{marginBottom:14}}>
          <label style={{fontSize:".74rem",fontWeight:600,color:"rgba(255,255,255,.6)",display:"block",marginBottom:5}}>Usuário</label>
          <input value={username} onChange={e=>setUsername(e.target.value)}
            placeholder="seu_usuario"
            style={{...inputStyle}} onKeyDown={e=>e.key==="Enter"&&(mode==="login"?handleLogin():handleRegister())}/>
        </div>
        <div style={{marginBottom:20}}>
          <label style={{fontSize:".74rem",fontWeight:600,color:"rgba(255,255,255,.6)",display:"block",marginBottom:5}}>Senha</label>
          <input type="password" value={password} onChange={e=>setPassword(e.target.value)}
            placeholder="••••••••"
            style={{...inputStyle}} onKeyDown={e=>e.key==="Enter"&&(mode==="login"?handleLogin():handleRegister())}/>
        </div>

        {error && (
          <div style={{background:"rgba(217,79,59,.15)",border:"1px solid rgba(217,79,59,.3)",borderRadius:10,padding:"8px 12px",
            fontSize:".78rem",color:"#FF8A80",marginBottom:14,textAlign:"center"}}>
            {error}
          </div>
        )}

        <button onClick={mode==="login"?handleLogin:handleRegister} disabled={loading}
          style={{width:"100%",padding:"13px",borderRadius:14,border:"none",
            background:loading?"rgba(255,255,255,.1)":"linear-gradient(135deg,#D94F3B,#C0392B)",
            color:loading?"rgba(255,255,255,.4)":"#fff",fontSize:".92rem",fontWeight:700,
            fontFamily:"inherit",cursor:loading?"not-allowed":"pointer",
            boxShadow:loading?"none":"0 4px 18px rgba(217,79,59,.4)",
            transition:"all .2s",
          }}>
          {loading?"Aguarde...":(mode==="login"?"Entrar →":"Criar conta →")}
        </button>

        <p style={{textAlign:"center",fontSize:".72rem",color:"rgba(255,255,255,.3)",marginTop:16,lineHeight:1.5}}>
          {mode==="login"?"Não tem conta? ":"Já tem conta? "}
          <button onClick={()=>{setMode(mode==="login"?"register":"login");setError("");}}
            style={{background:"none",border:"none",color:"rgba(217,79,59,.8)",fontWeight:700,cursor:"pointer",fontFamily:"inherit",fontSize:".72rem"}}>
            {mode==="login"?"Criar agora":"Entrar"}
          </button>
        </p>
      </div>
    </div>
  );
});

const inputStyle = {
  width:"100%", padding:"11px 14px", borderRadius:12,
  background:"rgba(255,255,255,.08)", border:"1px solid rgba(255,255,255,.12)",
  color:"#fff", fontSize:".9rem", fontFamily:"'Outfit',sans-serif",
  outline:"none", boxSizing:"border-box", transition:"border .2s",
};

// ── PROFILE MODAL ─────────────────────────────────────────────────────────
const ProfileModal = memo(function ProfileModal({ user, srsData, learnedLessons, reviewHistory, onClose, onUpdate, onLogout }) {
  const [editing, setEditing] = useState(false);
  const [displayName, setDisplayName] = useState(user.displayName);
  const [bio, setBio] = useState(user.bio || "");
  const [photo, setPhoto] = useState(user.photo || null);
  const [saving, setSaving] = useState(false);
  const fileRef = useRef(null);

  const jlpt = calcJLPT(srsData, learnedLessons, reviewHistory);

  const handlePhoto = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    if (file.size > 500000) { alert("Foto muito grande. Use uma imagem menor que 500KB."); return; }
    const reader = new FileReader();
    reader.onload = ev => setPhoto(ev.target.result);
    reader.readAsDataURL(file);
  };

  const handleSave = async () => {
    setSaving(true);
    const updated = { ...user, displayName: displayName.trim()||user.displayName, bio: bio.trim(), photo };
    await dbSaveUser(updated);
    onUpdate(updated);
    setSaving(false);
    setEditing(false);
  };

  // JLPT progress segments
  const levels = [
    { id:"N5", label:"N5", desc:"Kana + vocabulário básico", color:"#5BAD5E",  min:0,  max:100, current: jlpt.n5Score },
    { id:"N4", label:"N4", desc:"~300 palavras + gramática", color:"#3A8FD9",  min:0,  max:100, current: 0 },
    { id:"N3", label:"N3", desc:"~650 palavras",              color:"#E8853A",  min:0,  max:100, current: 0 },
    { id:"N2", label:"N2", desc:"~1500 palavras",             color:"#7B5CD9",  min:0,  max:100, current: 0 },
    { id:"N1", label:"N1", desc:"~2000 palavras + nuances",   color:"#D94F3B",  min:0,  max:100, current: 0 },
  ];

  const studyDays = jlpt.totalReviews > 0
    ? Math.ceil((Date.now() - (user.createdAt || Date.now())) / 86400000)
    : 0;

  return (
    <div style={PS.overlay} onClick={onClose}>
      <div style={PS.sheet} onClick={e=>e.stopPropagation()}>
        <button style={PS.x} onClick={onClose}>✕</button>

        {/* Header with photo + name */}
        <div style={PS.heroSection}>
          {/* Avatar */}
          <div style={{position:"relative",display:"inline-block"}}>
            <div style={{
              width:88,height:88,borderRadius:"50%",overflow:"hidden",
              border:"3px solid #fff",boxShadow:"0 4px 20px rgba(0,0,0,.2)",
              background:"linear-gradient(135deg,#D94F3B,#7B5CD9)",
              display:"flex",alignItems:"center",justifyContent:"center",
              cursor:editing?"pointer":"default",
            }} onClick={()=>editing&&fileRef.current?.click()}>
              {photo
                ? <img src={photo} style={{width:"100%",height:"100%",objectFit:"cover"}} alt="avatar"/>
                : <span style={{fontFamily:"'Noto Sans JP',sans-serif",fontSize:"2.5rem",fontWeight:900,color:"#fff"}}>
                    {(user.displayName||"?")[0]}
                  </span>
              }
            </div>
            {editing && (
              <div style={{
                position:"absolute",bottom:0,right:0,width:26,height:26,
                background:"#D94F3B",borderRadius:"50%",border:"2px solid #fff",
                display:"flex",alignItems:"center",justifyContent:"center",
                cursor:"pointer",fontSize:".75rem",
              }} onClick={()=>fileRef.current?.click()}>📷</div>
            )}
            <input ref={fileRef} type="file" accept="image/*" style={{display:"none"}} onChange={handlePhoto}/>
          </div>

          {/* Name + badge */}
          <div style={{flex:1,minWidth:0}}>
            {editing
              ? <input value={displayName} onChange={e=>setDisplayName(e.target.value)}
                  style={{...PS.editInput,fontSize:"1.1rem",fontWeight:700,marginBottom:6}}/>
              : <div style={{fontSize:"1.2rem",fontWeight:800,color:"#2D2A26",marginBottom:4}}>{user.displayName}</div>
            }
            <div style={{fontSize:".74rem",color:"#8A8580",marginBottom:6}}>@{user.username}</div>
            {/* Level badge */}
            <div style={{
              display:"inline-flex",alignItems:"center",gap:6,
              background:jlpt.badge.color+"18",border:`1px solid ${jlpt.badge.color}40`,
              borderRadius:20,padding:"4px 12px",
            }}>
              <span style={{fontSize:"1rem"}}>{jlpt.badge.emoji}</span>
              <span style={{fontSize:".78rem",fontWeight:700,color:jlpt.badge.color}}>{jlpt.badge.l}</span>
              <span style={{fontSize:".7rem",color:jlpt.badge.color,opacity:.7}}>— {jlpt.level}</span>
            </div>
          </div>
        </div>

        {/* Bio */}
        <div style={{padding:"0 20px",marginBottom:16}}>
          {editing
            ? <textarea value={bio} onChange={e=>setBio(e.target.value)}
                placeholder="Fale um pouco sobre você ou seus objetivos com o japonês..."
                style={{...PS.editInput,height:60,resize:"none",fontSize:".8rem"}}/>
            : bio
              ? <p style={{fontSize:".82rem",color:"#5A4A3A",lineHeight:1.5,margin:0}}>{bio}</p>
              : <p style={{fontSize:".78rem",color:"#B0A8A0",fontStyle:"italic",margin:0}}>Nenhuma bio adicionada.</p>
          }
        </div>

        {/* Stats row */}
        <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:6,padding:"0 20px",marginBottom:16}}>
          {[
            {v:jlpt.seen,     l:"Cards vistos"},
            {v:jlpt.mastered, l:"Dominados"},
            {v:Math.round(jlpt.retention)+"%", l:"Retenção"},
            {v:studyDays+"d", l:"Estudando"},
          ].map(({v,l})=>(
            <div key={l} style={{background:"#F9F7F3",borderRadius:12,padding:"10px 6px",textAlign:"center"}}>
              <div style={{fontSize:"1.1rem",fontWeight:800,color:"#2D2A26"}}>{v}</div>
              <div style={{fontSize:".6rem",color:"#8A8580",marginTop:1,fontWeight:600}}>{l}</div>
            </div>
          ))}
        </div>

        {/* JLPT Progress */}
        <div style={{padding:"0 20px",marginBottom:20}}>
          <div style={{fontSize:".8rem",fontWeight:700,color:"#2D2A26",marginBottom:12}}>📊 Progresso JLPT</div>
          {levels.map((lv,i) => {
            const locked = i > 0; // N4+ not unlockable yet in app
            const pct = locked ? 0 : lv.current;
            const achieved = pct >= 90;
            return (
              <div key={lv.id} style={{marginBottom:10}}>
                <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:4}}>
                  {/* Level pill */}
                  <div style={{
                    width:38,height:38,borderRadius:12,flexShrink:0,
                    background:achieved?lv.color:locked?"#F0EDE8":lv.color+"20",
                    display:"flex",alignItems:"center",justifyContent:"center",
                    border:`2px solid ${achieved?lv.color:locked?"#E0DDD8":lv.color+"40"}`,
                  }}>
                    <span style={{fontSize:".78rem",fontWeight:800,color:achieved?"#fff":locked?"#C0BBB5":lv.color}}>
                      {achieved?"✓":lv.id}
                    </span>
                  </div>
                  <div style={{flex:1}}>
                    <div style={{display:"flex",justifyContent:"space-between",marginBottom:3}}>
                      <span style={{fontSize:".78rem",fontWeight:700,color:locked?"#B0A8A0":"#2D2A26"}}>{lv.desc}</span>
                      <span style={{fontSize:".74rem",fontWeight:700,color:locked?"#C0BBB5":pct>=90?lv.color:"#8A8580"}}>
                        {locked?"🔒":pct+"%" }
                      </span>
                    </div>
                    <div style={{height:7,background:"#F0EDE8",borderRadius:4,overflow:"hidden"}}>
                      <div style={{
                        height:"100%",borderRadius:4,
                        background:locked?"#E0DDD8":`linear-gradient(90deg,${lv.color},${lv.color}cc)`,
                        width:pct+"%",transition:"width .6s ease",
                        boxShadow:pct>0&&!locked?`0 0 8px ${lv.color}60`:"none",
                      }}/>
                    </div>
                  </div>
                </div>
              </div>
            );
          })}
          <div style={{fontSize:".72rem",color:"#B0A8A0",marginTop:4,textAlign:"center"}}>
            N4 a N1 desbloqueiam com vocabulário e gramática avançada (em breve)
          </div>
        </div>

        {/* Actions */}
        <div style={{padding:"0 20px 20px",display:"flex",gap:8,flexDirection:"column"}}>
          {editing
            ? <div style={{display:"flex",gap:8}}>
                <button onClick={()=>{setEditing(false);setDisplayName(user.displayName);setBio(user.bio||"");setPhoto(user.photo);}}
                  style={{...PS.btnSecondary,flex:1}}>Cancelar</button>
                <button onClick={handleSave} disabled={saving}
                  style={{...PS.btnPrimary,flex:2}}>{saving?"Salvando...":"Salvar ✓"}</button>
              </div>
            : <button onClick={()=>setEditing(true)} style={PS.btnSecondary}>✏ Editar perfil</button>
          }
          <button onClick={async()=>{await dbClearSession();onLogout();}}
            style={{...PS.btnDanger}}>Sair da conta</button>
        </div>
      </div>
    </div>
  );
});

const PS = {
  overlay:{position:"fixed",inset:0,background:"rgba(0,0,0,.55)",backdropFilter:"blur(6px)",zIndex:2000,display:"flex",justifyContent:"center",alignItems:"flex-end",padding:"0"},
  sheet:{background:"#fff",borderRadius:"24px 24px 0 0",width:"100%",maxWidth:480,margin:"0 auto",maxHeight:"92vh",overflowY:"auto",position:"relative",boxShadow:"0 -12px 40px rgba(0,0,0,.2)"},
  heroSection:{display:"flex",alignItems:"center",gap:16,padding:"24px 20px 16px"},
  x:{position:"absolute",top:14,right:16,background:"none",border:"none",fontSize:"1.2rem",color:"#B0A8A0",width:30,height:30,borderRadius:"50%",display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer"},
  editInput:{width:"100%",padding:"8px 12px",borderRadius:10,border:"1.5px solid #E0DDD8",fontSize:".88rem",fontFamily:"'Outfit',sans-serif",outline:"none",color:"#2D2A26",boxSizing:"border-box"},
  btnPrimary:{padding:"11px",borderRadius:12,border:"none",background:"#D94F3B",color:"#fff",fontSize:".86rem",fontWeight:700,fontFamily:"inherit",cursor:"pointer"},
  btnSecondary:{padding:"11px",borderRadius:12,border:"1.5px solid #E0DDD8",background:"#fff",color:"#5A4A3A",fontSize:".86rem",fontWeight:600,fontFamily:"inherit",cursor:"pointer"},
  btnDanger:{padding:"11px",borderRadius:12,border:"1.5px solid #FFCDD2",background:"#FFF5F5",color:"#D94F3B",fontSize:".84rem",fontWeight:600,fontFamily:"inherit",cursor:"pointer"},
};

