/* ── AUDIO — Google TTS (voz nativa japonesa) ── */
// Usa o mesmo engine do Google Tradutor via elemento Audio.
// Sem API key, sem custo, qualidade nativa japonesa.
// Fallback automático para Web Speech API se o Google TTS falhar.

let _currentAudio = null;

function speak(text) {
  if (!text || !text.trim()) return;

  // Cancela o que estiver tocando
  if (_currentAudio) {
    _currentAudio.pause();
    _currentAudio.src = "";
    _currentAudio = null;
  }
  if (window.speechSynthesis) window.speechSynthesis.cancel();

  // Limpa pontuação para TTS mais limpo
  const clean = text.replace(/[。、！？「」『』【】・\s]/g, c =>
    ['。','！','？'].includes(c) ? '.' : ' '
  ).trim();

  // Google TTS — mesma engine do Google Tradutor
  const url = `https://translate.google.com/translate_tts?ie=UTF-8&q=${encodeURIComponent(clean)}&tl=ja&client=tw-ob&ttsspeed=0.8`;

  const audio = new Audio(url);
  audio.volume = 1.0;
  _currentAudio = audio;

  const playPromise = audio.play();
  if (playPromise !== undefined) {
    playPromise.catch(() => _fallbackSpeak(text));
  }
}

function _fallbackSpeak(text) {
  if (!window.speechSynthesis) return;
  const u = new SpeechSynthesisUtterance(text);
  u.lang = "ja-JP";
  u.rate = 0.75;
  u.pitch = 1.0;
  const voices = window.speechSynthesis.getVoices();
  // Prefer high-quality Japanese voices
  const preferred = [
    voices.find(v => v.lang === "ja-JP" && v.localService),
    voices.find(v => v.lang.startsWith("ja")),
  ].find(Boolean);
  if (preferred) u.voice = preferred;
  window.speechSynthesis.speak(u);
}

/* ═══════════════════════════════════════════════════════════════════════════
   FULL ANKI SM-2 IMPLEMENTATION
   4 phases: new → learning → review → relearning
   Matches Anki default settings exactly.
   ═══════════════════════════════════════════════════════════════════════════ */

const DEFAULT_SETTINGS = {
  learningSteps:    [1, 10],   // minutes — "1m 10m" (Anki default)
  relearningSteps:  [10],      // minutes after lapse
  graduatingInterval: 1,       // days after completing learning
  easyInterval:     4,         // days when pressing Easy on new/learning card
  startingEase:     2.5,       // initial ease factor
  easyBonus:        1.30,      // multiplier for Easy in review
  hardFactor:       1.20,      // multiplier for Hard in review
  intervalModifier: 1.0,       // global multiplier (like Anki's interval modifier)
  maxInterval:      36500,     // ~100 years cap
  newPerDay:        20,        // new cards per day
  reviewsPerDay:    200,       // review cards per day
};

const MIN  = 60 * 1000;          // 1 minute in ms
const DAY  = 86400 * 1000;       // 1 day in ms

// Format an ms duration to a human-readable string
function fmtMs(ms) {
  const mins = Math.round(ms / MIN);
  if (mins < 60)  return `${mins}min`;
  const hrs  = Math.round(ms / (3600 * 1000));
  if (hrs  < 24)  return `${hrs}h`;
  const days = Math.round(ms / DAY);
  if (days < 30)  return `${days}d`;
  if (days < 365) return `${Math.round(days/30)}m`;
  return `${Math.round(days/365)}a`;
}

// Core SM-2: given card state + button pressed → returns next card state
// quality: 1=Again  2=Hard  3=Good  4=Easy
function computeCard(card, quality, settings = DEFAULT_SETTINGS) {
  const now    = Date.now();
  const state  = card?.state    || "new";
  const step   = card?.step     || 0;
  const ease   = card?.ease     || settings.startingEase;
  const interval = card?.interval || 0;
  const lapses = card?.lapses   || 0;
  const reps   = card?.reps     || 0;

  // ── NEW ─────────────────────────────────────────────────────────────────
  if (state === "new") {
    if (quality === 4) { // Easy → skip learning, go straight to review
      return { state:"review", ease:settings.startingEase, interval:settings.easyInterval,
        step:0, lapses, reps:1, due:now+settings.easyInterval*DAY, lastReview:now };
    }
    if (quality === 3) { // Good → step 1 (or graduate if only 1 step)
      if (settings.learningSteps.length > 1) {
        return { state:"learning", ease:settings.startingEase, interval:0,
          step:1, lapses, reps, due:now+settings.learningSteps[1]*MIN, lastReview:now };
      }
      return { state:"review", ease:settings.startingEase, interval:settings.graduatingInterval,
        step:0, lapses, reps:1, due:now+settings.graduatingInterval*DAY, lastReview:now };
    }
    // Again or Hard → step 0
    return { state:"learning", ease:settings.startingEase, interval:0,
      step:0, lapses, reps, due:now+settings.learningSteps[0]*MIN, lastReview:now };
  }

  // ── LEARNING ─────────────────────────────────────────────────────────────
  if (state === "learning") {
    const total = settings.learningSteps.length;
    if (quality === 4) { // Easy → graduate
      return { state:"review", ease:settings.startingEase, interval:settings.easyInterval,
        step:0, lapses, reps:reps+1, due:now+settings.easyInterval*DAY, lastReview:now };
    }
    if (quality === 3) { // Good → next step or graduate
      const next = step + 1;
      if (next >= total) {
        return { state:"review", ease:settings.startingEase, interval:settings.graduatingInterval,
          step:0, lapses, reps:reps+1, due:now+settings.graduatingInterval*DAY, lastReview:now };
      }
      return { state:"learning", ease:settings.startingEase, interval:0,
        step:next, lapses, reps, due:now+settings.learningSteps[next]*MIN, lastReview:now };
    }
    if (quality === 2) { // Hard → stay on current step
      return { state:"learning", ease:settings.startingEase, interval:0,
        step, lapses, reps, due:now+settings.learningSteps[step]*MIN, lastReview:now };
    }
    // Again → back to step 0
    return { state:"learning", ease:settings.startingEase, interval:0,
      step:0, lapses, reps, due:now+settings.learningSteps[0]*MIN, lastReview:now };
  }

  // ── REVIEW ───────────────────────────────────────────────────────────────
  if (state === "review") {
    if (quality === 1) { // Again → lapse, enter relearning
      const newEase = Math.max(1.3, ease - 0.2);
      const lapseInterval = Math.max(1, Math.round(interval * 0.0)); // Anki resets interval
      return { state:"relearning", ease:newEase, interval:lapseInterval,
        step:0, lapses:lapses+1, reps, due:now+settings.relearningSteps[0]*MIN, lastReview:now };
    }
    if (quality === 2) { // Hard
      const newInterval = Math.max(interval+1,
        Math.min(Math.round(interval * settings.hardFactor * settings.intervalModifier), settings.maxInterval));
      const newEase = Math.max(1.3, ease - 0.15);
      return { state:"review", ease:Math.round(newEase*100)/100, interval:newInterval,
        step:0, lapses, reps:reps+1, due:now+newInterval*DAY, lastReview:now };
    }
    if (quality === 3) { // Good
      const newInterval = Math.max(interval+1,
        Math.min(Math.round(interval * ease * settings.intervalModifier), settings.maxInterval));
      return { state:"review", ease:Math.round(ease*100)/100, interval:newInterval,
        step:0, lapses, reps:reps+1, due:now+newInterval*DAY, lastReview:now };
    }
    // Easy
    const newInterval = Math.max(interval+1,
      Math.min(Math.round(interval * ease * settings.easyBonus * settings.intervalModifier), settings.maxInterval));
    const newEase = Math.min(ease + 0.15, 4.0);
    return { state:"review", ease:Math.round(newEase*100)/100, interval:newInterval,
      step:0, lapses, reps:reps+1, due:now+newInterval*DAY, lastReview:now };
  }

  // ── RELEARNING ────────────────────────────────────────────────────────────
  if (state === "relearning") {
    const total = settings.relearningSteps.length;
    if (quality === 4) { // Easy → graduate relearning
      const newInterval = Math.max(1, Math.round(interval * settings.intervalModifier));
      return { state:"review", ease, interval:newInterval,
        step:0, lapses, reps:reps+1, due:now+newInterval*DAY, lastReview:now };
    }
    if (quality === 3) { // Good → next step or graduate
      const next = step + 1;
      if (next >= total) {
        const newInterval = Math.max(1, Math.round(interval * settings.intervalModifier));
        return { state:"review", ease, interval:newInterval,
          step:0, lapses, reps:reps+1, due:now+newInterval*DAY, lastReview:now };
      }
      return { state:"relearning", ease, interval,
        step:next, lapses, reps, due:now+settings.relearningSteps[next]*MIN, lastReview:now };
    }
    if (quality === 2) { // Hard → same step
      return { state:"relearning", ease, interval,
        step, lapses, reps, due:now+settings.relearningSteps[step]*MIN, lastReview:now };
    }
    // Again → step 0
    return { state:"relearning", ease, interval,
      step:0, lapses, reps, due:now+settings.relearningSteps[0]*MIN, lastReview:now };
  }

  return card; // fallback
}

// Returns [again_label, hard_label, good_label, easy_label] preview strings
function previewAllIntervals(card, settings = DEFAULT_SETTINGS) {
  const now = Date.now();
  return [1,2,3,4].map(q => {
    const next = computeCard(card, q, settings);
    return fmtMs(next.due - now);
  });
}

// Card state label for UI
function stateLabel(card) {
  if (!card) return { txt:"🆕 Novo", color:"#3A8FD9" };
  if (card.state === "new")        return { txt:"🆕 Novo",      color:"#3A8FD9" };
  if (card.state === "learning")   return { txt:`📖 Aprendendo (passo ${(card.step||0)+1})`, color:"#E8853A" };
  if (card.state === "relearning") return { txt:`🔁 Reaprendendo (${card.lapses} falha${card.lapses!==1?"s":""})`, color:"#D94F3B" };
  if (card.interval >= 21)         return { txt:`⭐ Dominado (${card.interval}d)`, color:"#7B5CD9" };
  return { txt:`🔄 Revisão (${card.interval}d)`, color:"#5BAD5E" };
}


