const ParticlePracticeTab = memo(function ParticlePracticeTab({ speak }) {
  const [mode, setMode]         = useState("menu");
  const [filterP, setFilterP]   = useState("all");
  const [filterDiff, setFilterDiff] = useState("all"); // all | easy | medium | hard
  const [queue, setQueue]       = useState([]);
  const [qIdx, setQIdx]         = useState(0);
  const [chosen, setChosen]     = useState(null);
  const [feedback, setFeedback] = useState(null);
  const [score, setScore]       = useState({c:0, t:0, streak:0, maxStreak:0, wrong:[]});
  const [history, setHistory]   = useState({});
  const [showGuide, setShowGuide] = useState(false);
  const [activeGuide, setActiveGuide] = useState(null);

  const allParticles = [...new Set(PARTICLE_SENTENCES.map(s=>s.p))];

  const particleStats = useMemo(()=>{
    const stats = {};
    for (const [id, h] of Object.entries(history)) {
      const sent = PARTICLE_SENTENCES.find(s=>s.id===id);
      if (!sent) continue;
      const p = sent.p;
      if (!stats[p]) stats[p]={seen:0,correct:0};
      stats[p].seen    += h.seen;
      stats[p].correct += h.correct;
    }
    return stats;
  }, [history]);

  const globalSeen    = Object.values(history).reduce((s,h)=>s+h.seen,0);
  const globalCorrect = Object.values(history).reduce((s,h)=>s+h.correct,0);
  const globalRate    = globalSeen>0 ? Math.round((globalCorrect/globalSeen)*100) : null;

  // Smart queue: weak particles first, then shuffle
  const buildQueue = (pFilter="all", dFilter="all") => {
    let pool = PARTICLE_SENTENCES;
    if (pFilter !== "all") pool = pool.filter(s=>s.p===pFilter);
    if (dFilter !== "all") pool = pool.filter(s=>s.diff===dFilter);
    return [...pool].sort((a,b)=>{
      const ha = history[a.id], hb = history[b.id];
      const ra = ha ? ha.correct/ha.seen : 0.5;
      const rb = hb ? hb.correct/hb.seen : 0.5;
      return ra - rb + (Math.random()-.5)*.25;
    });
  };

  const startPractice = (pF="all", dF="all") => {
    setFilterP(pF); setFilterDiff(dF);
    setQueue(buildQueue(pF, dF));
    setQIdx(0); setChosen(null); setFeedback(null);
    setScore({c:0,t:0,streak:0,maxStreak:0,wrong:[]});
    setMode("practice");
  };

  const cur              = queue[qIdx];
  const correctParticle  = cur?.p;
  const pInfo            = cur ? PARTICLES_INFO[correctParticle] : null;

  const options = useMemo(()=>{
    if (!cur) return [];
    // Confusable pairs (often mixed up)
    const confusable = {
      "は":["が","も"], "が":["は","を"], "を":["が","に"],
      "に":["で","へ"], "で":["に","と"], "の":["が","を"],
      "と":["も","で"], "も":["は","が"], "か":["は","が"],
      "へ":["に","で"], "から":["まで","に"], "まで":["から","に"],
    };
    const preferred = confusable[correctParticle] || [];
    const others = allParticles.filter(p=>p!==correctParticle);
    // Prefer confusable particles as distractors
    const confusablePicks = others.filter(p=>preferred.includes(p));
    const remaining       = others.filter(p=>!preferred.includes(p)).sort(()=>Math.random()-.5);
    const distractors     = [...confusablePicks, ...remaining].slice(0,3);
    return [...distractors, correctParticle].sort(()=>Math.random()-.5);
  }, [qIdx, queue.length]);

  const pick = (p) => {
    if (chosen) return;
    setChosen(p);
    const ok = p === correctParticle;
    setFeedback({correct:ok});
    setHistory(prev=>{
      const prev_ = prev[cur.id]||{seen:0,correct:0};
      return {...prev, [cur.id]:{seen:prev_.seen+1, correct:prev_.correct+(ok?1:0)}};
    });
    setScore(s=>{
      const newStreak = ok ? s.streak+1 : 0;
      return {
        c:s.c+(ok?1:0), t:s.t+1,
        streak:newStreak, maxStreak:Math.max(s.maxStreak,newStreak),
        wrong:ok?s.wrong:[...s.wrong,cur],
      };
    });
  };

  const next = () => {
    if (qIdx+1>=queue.length) setMode("result");
    else { setQIdx(i=>i+1); setChosen(null); setFeedback(null); }
  };

  /* ────────────────────────────────── MENU ─────────────────────────────────── */
  if (mode==="menu") return (
    <div className="fi">
      {/* Hero */}
      <div style={{
        background:"linear-gradient(135deg,#7B0050,#E91E8C)",
        borderRadius:20,padding:"18px 20px 16px",marginBottom:14,
        position:"relative",overflow:"hidden",
      }}>
        <div style={{
          position:"absolute",right:-10,top:-10,
          fontFamily:"'Noto Sans JP',sans-serif",fontSize:"8rem",fontWeight:900,
          color:"rgba(255,255,255,.05)",lineHeight:1,
        }}>助</div>
        <div style={{fontSize:".7rem",color:"rgba(255,255,255,.75)",marginBottom:3}}>
          ✏️ Fill-in-the-Blanks
        </div>
        <div style={{fontSize:"1.05rem",fontWeight:800,color:"#fff",marginBottom:8}}>
          Partículas japonesas
        </div>
        <div style={{fontSize:".76rem",color:"rgba(255,255,255,.8)",lineHeight:1.6,marginBottom:12}}>
          Preencha a partícula correta. O sistema prioriza automaticamente as que você mais erra.
        </div>

        {/* Particle mastery chips */}
        <div style={{display:"flex",gap:5,flexWrap:"wrap"}}>
          {Object.entries(PARTICLES_INFO).map(([p,info])=>{
            const st  = particleStats[p];
            const pct = st ? Math.round((st.correct/st.seen)*100) : null;
            const chipColor = pct===null?"rgba(255,255,255,.12)":
                              pct>=80?"rgba(91,173,94,.3)":
                              pct>=60?"rgba(232,133,58,.3)":"rgba(217,79,59,.3)";
            return (
              <div key={p} style={{
                display:"flex",flexDirection:"column",alignItems:"center",gap:2,
                background:chipColor,borderRadius:10,padding:"5px 8px",
                minWidth:36,border:"1px solid rgba(255,255,255,.1)",
              }}>
                <span style={{
                  fontFamily:"'Noto Sans JP',sans-serif",
                  fontSize:"1rem",fontWeight:900,color:"#fff",
                }}>{p}</span>
                <span style={{
                  fontSize:".52rem",fontWeight:700,
                  color:pct===null?"rgba(255,255,255,.4)":pct>=80?"#A5D6A7":pct>=60?"#FFD180":"#FFCDD2",
                }}>{pct===null?"—":pct+"%"}</span>
              </div>
            );
          })}
        </div>

        {/* Global stats */}
        {globalSeen>0 && (
          <div style={{
            marginTop:12,display:"flex",gap:8,
            background:"rgba(255,255,255,.1)",borderRadius:11,padding:"8px 12px",
          }}>
            <div style={{textAlign:"center",flex:1,borderRight:"1px solid rgba(255,255,255,.15)"}}>
              <div style={{fontSize:".9rem",fontWeight:800,color:"#fff"}}>{globalSeen}</div>
              <div style={{fontSize:".56rem",color:"rgba(255,255,255,.6)"}}>Tentativas</div>
            </div>
            <div style={{textAlign:"center",flex:1,borderRight:"1px solid rgba(255,255,255,.15)"}}>
              <div style={{fontSize:".9rem",fontWeight:800,color:globalRate>=80?"#A5D6A7":globalRate>=60?"#FFD180":"#FFCDD2"}}>{globalRate}%</div>
              <div style={{fontSize:".56rem",color:"rgba(255,255,255,.6)"}}>Acurácia</div>
            </div>
            <div style={{textAlign:"center",flex:1}}>
              <div style={{fontSize:".9rem",fontWeight:800,color:"#fff"}}>{PARTICLE_SENTENCES.length}</div>
              <div style={{fontSize:".56rem",color:"rgba(255,255,255,.6)"}}>Frases</div>
            </div>
          </div>
        )}
      </div>

      {/* Quick start */}
      <button onClick={()=>startPractice("all","all")} style={{
        width:"100%",padding:"14px",borderRadius:16,border:"none",
        background:"linear-gradient(135deg,#E91E8C,#C2185B)",
        color:"#fff",fontSize:"1rem",fontWeight:700,
        fontFamily:"inherit",cursor:"pointer",marginBottom:12,
        boxShadow:"0 4px 16px rgba(41,128,185,.35)",
        display:"flex",alignItems:"center",justifyContent:"center",gap:10,
      }}>
        <span style={{fontSize:"1.2rem"}}>🎯</span>
        <div style={{textAlign:"left"}}>
          <div>Praticar todas as partículas</div>
          <div style={{fontSize:".7rem",opacity:.8}}>{PARTICLE_SENTENCES.length} frases · inteligente</div>
        </div>
        <span style={{opacity:.7,fontSize:"1rem",marginLeft:"auto"}}>→</span>
      </button>

      {/* Difficulty filter */}
      <div style={{
        background:"#fff",borderRadius:14,padding:"12px 14px",
        marginBottom:12,border:"1.5px solid #EDEAE4",
        boxShadow:"0 1px 5px rgba(0,0,0,.04)",
      }}>
        <div style={{fontSize:".7rem",fontWeight:700,color:"#8A8580",
          textTransform:"uppercase",letterSpacing:".5px",marginBottom:8}}>
          Por dificuldade
        </div>
        <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:6}}>
          {[
            {id:"easy",   label:"Fácil",    icon:"🌱", color:"#5BAD5E",
             count:PARTICLE_SENTENCES.filter(s=>s.diff==="easy").length},
            {id:"medium", label:"Médio",    icon:"⚡", color:"#E8853A",
             count:PARTICLE_SENTENCES.filter(s=>s.diff==="medium").length},
            {id:"hard",   label:"Difícil",  icon:"🔥", color:"#D94F3B",
             count:PARTICLE_SENTENCES.filter(s=>s.diff==="hard").length},
          ].map(d=>(
            <button key={d.id} onClick={()=>startPractice("all",d.id)} style={{
              padding:"10px 6px",borderRadius:12,border:"none",
              background:d.color+"0e",cursor:"pointer",fontFamily:"inherit",
              textAlign:"center",
              border:`1.5px solid ${d.color}25`,
              transition:"all .14s",
              display:"flex",flexDirection:"column",alignItems:"center",gap:3,
            }}>
              <span style={{fontSize:"1.1rem"}}>{d.icon}</span>
              <span style={{fontSize:".74rem",fontWeight:700,color:d.color}}>{d.label}</span>
              <span style={{fontSize:".6rem",color:"#B0A8A0"}}>{d.count} frases</span>
            </button>
          ))}
        </div>
      </div>

      {/* Particle guide */}
      <div style={{
        background:"#fff",borderRadius:14,overflow:"hidden",
        border:"1.5px solid #EDEAE4",boxShadow:"0 1px 5px rgba(0,0,0,.04)",
      }}>
        <button onClick={()=>setShowGuide(v=>!v)} style={{
          width:"100%",display:"flex",alignItems:"center",gap:8,
          padding:"12px 14px",background:"none",border:"none",
          cursor:"pointer",fontFamily:"inherit",
        }}>
          <span style={{fontSize:".9rem"}}>📖</span>
          <span style={{fontSize:".82rem",fontWeight:600,color:"#2D2A26",flex:1,textAlign:"left"}}>
            Guia rápido das partículas
          </span>
          <span style={{
            fontSize:".6rem",color:showGuide?"#E91E8C":"#C0BBB5",
            transform:showGuide?"rotate(90deg)":"none",transition:"transform .2s",
          }}>▶</span>
        </button>
        {showGuide && (
          <div style={{borderTop:"1px solid #F0EDE8"}}>
            {Object.entries(PARTICLES_INFO).map(([p,info],i)=>(
              <div key={p}>
                <button onClick={()=>setActiveGuide(activeGuide===p?null:p)} style={{
                  width:"100%",display:"flex",alignItems:"center",gap:12,
                  padding:"10px 14px",background:"none",border:"none",
                  cursor:"pointer",fontFamily:"inherit",textAlign:"left",
                  borderBottom:`1px solid ${activeGuide===p?info.color+"20":"#F5F3EE"}`,
                  background:activeGuide===p?info.color+"06":"transparent",
                }}>
                  <div style={{
                    width:36,height:36,borderRadius:10,flexShrink:0,
                    background:info.color,
                    display:"flex",alignItems:"center",justifyContent:"center",
                    fontFamily:"'Noto Sans JP',sans-serif",
                    fontSize:"1.1rem",fontWeight:900,color:"#fff",
                    boxShadow:`0 2px 6px ${info.color}35`,
                  }}>{p}</div>
                  <div style={{flex:1}}>
                    <div style={{fontSize:".78rem",fontWeight:700,color:"#2D2A26",marginBottom:1}}>
                      {info.role}
                    </div>
                    <div style={{fontSize:".68rem",color:"#8A8580",lineHeight:1.3}}>{info.tip}</div>
                  </div>
                  <button onClick={e=>{e.stopPropagation();speak(p);}} style={{
                    background:info.color+"14",border:"none",borderRadius:7,
                    padding:"4px 8px",cursor:"pointer",fontSize:".8rem",flexShrink:0,
                  }}>🔊</button>
                </button>
                {/* Expanded examples */}
                {activeGuide===p && (
                  <div style={{
                    padding:"8px 14px 10px",
                    background:info.color+"06",
                    borderBottom:"1px solid #F5F3EE",
                  }}>
                    {PARTICLE_SENTENCES.filter(s=>s.p===p).slice(0,2).map(s=>(
                      <div key={s.id} style={{marginBottom:5}}>
                        <div style={{fontFamily:"'Noto Sans JP',sans-serif",
                          fontSize:".9rem",fontWeight:700,color:"#2D2A26",lineHeight:1.5}}>
                          {s.parts.map((pt,pi)=>
                            pi===s.slot
                              ? <span key={pi} style={{
                                  color:info.color,fontWeight:900,
                                  background:info.color+"18",borderRadius:4,padding:"0 3px",
                                }}>{p}</span>
                              : <span key={pi}>{pt}</span>
                          )}
                        </div>
                        <div style={{fontSize:".68rem",color:"#8A8580",fontStyle:"italic"}}>{s.pt}</div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );

  /* ────────────────────────────────── RESULT ───────────────────────────────── */
  if (mode==="result") {
    const pct    = Math.round((score.c/score.t)*100);
    const gradC  = pct>=80?"#5BAD5E":pct>=60?"#E8853A":"#D94F3B";
    const emoji  = pct>=80?"🎉":pct>=60?"👏":"💪";
    return (
      <div className="fi">
        <div style={{
          background:`linear-gradient(135deg,${gradC},${gradC}bb)`,
          borderRadius:20,padding:"26px 20px 20px",textAlign:"center",
          marginBottom:14,boxShadow:`0 5px 20px ${gradC}30`,
          position:"relative",overflow:"hidden",
        }}>
          <div style={{position:"absolute",right:-10,top:-10,fontSize:"7rem",lineHeight:1,opacity:.1}}>{emoji}</div>
          <div style={{fontSize:"3rem",marginBottom:6}}>{emoji}</div>
          <div style={{fontSize:"3.5rem",fontWeight:900,color:"#fff",lineHeight:1,marginBottom:4,
            textShadow:"0 3px 10px rgba(0,0,0,.2)"}}>{pct}%</div>
          <div style={{fontSize:"1rem",fontWeight:700,color:"rgba(255,255,255,.95)",marginBottom:4}}>
            {pct>=80?"Partículas dominadas!":pct>=60?"Bom progresso!":"Continue praticando!"}
          </div>
          <div style={{fontSize:".78rem",color:"rgba(255,255,255,.8)",marginBottom:10}}>
            {score.c} de {score.t} corretas
          </div>
          {score.maxStreak>=3 && (
            <div style={{
              display:"inline-block",
              background:"rgba(255,255,255,.2)",borderRadius:20,
              padding:"4px 14px",fontSize:".76rem",fontWeight:700,color:"#fff",
            }}>🔥 Melhor sequência: {score.maxStreak} seguidas!</div>
          )}
        </div>

        {score.wrong.length>0 && (
          <div style={{background:"#fff",borderRadius:16,overflow:"hidden",
            boxShadow:"0 2px 12px rgba(0,0,0,.06)",marginBottom:12}}>
            <div style={{padding:"11px 16px",background:"#FDE8E808",
              borderBottom:"1px solid #FFCDD2",display:"flex",alignItems:"center",gap:7}}>
              <span style={{fontSize:".85rem"}}>❌</span>
              <div style={{fontSize:".84rem",fontWeight:700,color:"#C62828",flex:1}}>
                {score.wrong.length} para revisar
              </div>
            </div>
            <div>
              {score.wrong.map((s,i)=>{
                const info = PARTICLES_INFO[s.p];
                return (
                  <div key={s.id} style={{
                    padding:"11px 14px",
                    borderBottom:i<score.wrong.length-1?"1px solid #F5F3EE":"none",
                    background:i%2===0?"#fff":"#FDFCFA",
                  }}>
                    <div style={{fontFamily:"'Noto Sans JP',sans-serif",
                      fontSize:"1rem",fontWeight:700,color:"#2D2A26",marginBottom:4,lineHeight:1.5}}>
                      {s.parts.map((pt,pi)=>
                        pi===s.slot
                          ? <span key={pi} style={{background:info.color,color:"#fff",
                              borderRadius:6,padding:"1px 7px",margin:"0 2px",fontWeight:900}}>{s.p}</span>
                          : <span key={pi}>{pt}</span>
                      )}
                    </div>
                    <div style={{display:"flex",alignItems:"center",gap:8}}>
                      <div style={{fontSize:".62rem",fontWeight:700,color:info.color,
                        background:info.color+"12",borderRadius:7,padding:"2px 8px",
                        border:`1px solid ${info.color}25`}}>{s.p} — {info.role}</div>
                      <div style={{fontSize:".68rem",color:"#8A8580",fontStyle:"italic"}}>{s.pt}</div>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        )}

        <div style={{display:"flex",flexDirection:"column",gap:8}}>
          <button onClick={()=>startPractice(filterP,filterDiff)} style={{
            padding:"13px",borderRadius:14,border:"none",
            background:`linear-gradient(135deg,${gradC},${gradC}bb)`,
            color:"#fff",fontSize:".9rem",fontWeight:700,fontFamily:"inherit",cursor:"pointer",
            boxShadow:`0 3px 12px ${gradC}35`,
          }}>🔄 Praticar de novo</button>
          {score.wrong.length>0 && (
            <button onClick={()=>{
              setQueue(score.wrong); setQIdx(0); setChosen(null); setFeedback(null);
              setScore({c:0,t:0,streak:0,maxStreak:0,wrong:[]}); setMode("practice");
            }} style={{
              padding:"13px",borderRadius:14,border:"none",
              background:"linear-gradient(135deg,#E8853A,#D4702A)",
              color:"#fff",fontSize:".86rem",fontWeight:700,fontFamily:"inherit",cursor:"pointer",
            }}>📚 Revisar os erros ({score.wrong.length})</button>
          )}
          <button onClick={()=>setMode("menu")} style={{
            padding:"11px",borderRadius:12,fontFamily:"inherit",cursor:"pointer",
            border:"1.5px solid #E0DDD8",background:"#fff",
            fontSize:".84rem",color:"#8A8580",fontWeight:600,
          }}>← Escolher partícula</button>
        </div>
      </div>
    );
  }

  /* ────────────────────────────────── PRACTICE ─────────────────────────────── */
  if (!cur) return null;
  const progressPct = (qIdx/queue.length)*100;
  const isCorrect   = chosen === correctParticle;

  return (
    <div className="fi">
      {/* Progress header */}
      <div style={{
        background:"#fff",borderRadius:14,padding:"11px 14px",
        marginBottom:12,boxShadow:"0 1px 6px rgba(0,0,0,.05)",
      }}>
        <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:8}}>
          <button onClick={()=>setMode("menu")} style={{
            display:"flex",alignItems:"center",gap:3,
            background:"none",border:"1px solid #E0DDD8",borderRadius:8,
            padding:"4px 9px",fontSize:".7rem",fontWeight:600,
            color:"#8A8580",cursor:"pointer",fontFamily:"inherit",
          }}>‹ Sair</button>
          <div style={{flex:1,textAlign:"center"}}>
            <span style={{fontSize:".82rem",fontWeight:700,color:"#2D2A26"}}>{qIdx+1}</span>
            <span style={{fontSize:".78rem",color:"#B0A8A0"}}>/{queue.length}</span>
          </div>
          {score.streak>=3 && (
            <div style={{
              background:"linear-gradient(135deg,#FF6B35,#FF8C00)",
              color:"#fff",borderRadius:20,padding:"3px 9px",
              fontSize:".66rem",fontWeight:700,flexShrink:0,
            }}>🔥 {score.streak}×</div>
          )}
          <div style={{display:"flex",gap:8,flexShrink:0}}>
            <span style={{fontSize:".76rem",fontWeight:700,color:"#5BAD5E"}}>✓ {score.c}</span>
            <span style={{fontSize:".76rem",fontWeight:700,color:"#D94F3B"}}>✗ {score.t-score.c}</span>
          </div>
        </div>
        <div style={{height:5,background:"#F0EDE8",borderRadius:3,overflow:"hidden"}}>
          <div style={{height:"100%",borderRadius:3,
            background:"linear-gradient(90deg,#E91E8C,#E91E8C)",
            width:progressPct+"%",transition:"width .4s"}}/>
        </div>
      </div>

      {/* Sentence card */}
      <div style={{
        background:"#fff",borderRadius:20,padding:"22px 18px 18px",
        boxShadow:"0 4px 20px rgba(0,0,0,.08)",marginBottom:12,
      }}>
        <div style={{
          fontSize:".62rem",fontWeight:700,color:"#B0A8A0",
          textTransform:"uppercase",letterSpacing:".8px",marginBottom:14,textAlign:"center",
        }}>Qual partícula completa a frase?</div>

        {/* Sentence with blank */}
        <div style={{
          textAlign:"center",marginBottom:14,
          fontFamily:"'Noto Sans JP',sans-serif",
          fontSize:"clamp(1.3rem,5vw,1.8rem)",fontWeight:700,
          lineHeight:2,color:"#2D2A26",
        }}>
          {cur.parts.map((pt,pi)=>
            pi===cur.slot ? (
              <span key={pi} style={{
                display:"inline-block",
                minWidth:56,
                border:"none",
                borderBottom:`3px solid ${chosen
                  ? isCorrect ? pInfo?.color||"#E91E8C" : "#D94F3B"
                  : "#E91E8C"}`,
                padding:"0 10px",
                color:chosen
                  ? isCorrect ? pInfo?.color||"#E91E8C" : "#D94F3B"
                  : "transparent",
                fontWeight:900,
                background:chosen
                  ? isCorrect ? (pInfo?.color||"#E91E8C")+"14" : "#FDE8E8"
                  : "#FCE4EC",
                borderRadius:"8px 8px 0 0",
                transition:"all .25s",
                fontSize:"1.6rem",
              }}>{chosen || "　"}</span>
            ) : (
              <span key={pi}>{pt}</span>
            )
          )}
        </div>

        {/* Translation */}
        <div style={{
          textAlign:"center",fontSize:".8rem",color:"#8A8580",
          fontStyle:"italic",marginBottom:10,
        }}>{cur.pt}</div>

        {/* Difficulty + hint */}
        <div style={{
          display:"flex",alignItems:"center",gap:6,
          background:"#F9F7F3",borderRadius:10,padding:"7px 12px",
        }}>
          <span style={{
            fontSize:".58rem",fontWeight:700,padding:"2px 7px",borderRadius:6,
            background:cur.diff==="easy"?"#E8F5E9":cur.diff==="hard"?"#FDE8E8":"#FFF3E8",
            color:cur.diff==="easy"?"#2E7D32":cur.diff==="hard"?"#C62828":"#BF6000",
            flexShrink:0,
          }}>{cur.diff==="easy"?"🌱 Fácil":cur.diff==="hard"?"🔥 Difícil":"⚡ Médio"}</span>
          <span style={{fontSize:".7rem",color:"#5A4A3A",flex:1}}>💡 {cur.hint}</span>
        </div>
      </div>

      {/* Options — 2×2 grid */}
      {!chosen && (
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:12}}>
          {options.map(p=>{
            const info = PARTICLES_INFO[p];
            return (
              <button key={p} onClick={()=>pick(p)} style={{
                padding:"16px 10px",borderRadius:16,
                border:`2px solid ${info?.color+"25"||"#EDEAE4"}`,
                background:info?.color+"07"||"#fff",
                cursor:"pointer",fontFamily:"inherit",textAlign:"center",
                boxShadow:"0 1px 5px rgba(0,0,0,.04)",
                transition:"all .12s",
                display:"flex",flexDirection:"column",alignItems:"center",gap:5,
              }}>
                <span style={{
                  fontFamily:"'Noto Sans JP',sans-serif",
                  fontSize:"2.2rem",fontWeight:900,
                  color:info?.color||"#2D2A26",lineHeight:1,
                }}>{p}</span>
                <span style={{
                  fontSize:".64rem",fontWeight:600,color:info?.color||"#8A8580",
                  background:info?.color+"14"||"#F4F1EB",
                  borderRadius:6,padding:"2px 8px",
                }}>{info?.role||""}</span>
              </button>
            );
          })}
        </div>
      )}

      {/* Feedback */}
      {chosen && feedback && (
        <div style={{
          borderRadius:18,overflow:"hidden",marginBottom:12,
          border:`2px solid ${isCorrect?"#5BAD5E40":"#D94F3B40"}`,
          boxShadow:`0 4px 16px ${isCorrect?"#5BAD5E12":"#D94F3B12"}`,
        }}>
          <div style={{
            padding:"12px 16px",
            background:isCorrect?"linear-gradient(135deg,#E8F8E8,#F0FFF0)":"linear-gradient(135deg,#FDE8E8,#FFF0F0)",
            borderBottom:`1px solid ${isCorrect?"#A5D6A7":"#FFCDD2"}`,
            display:"flex",alignItems:"center",gap:10,
          }}>
            <div style={{
              width:36,height:36,borderRadius:10,flexShrink:0,
              background:isCorrect?"#5BAD5E":"#D94F3B",
              display:"flex",alignItems:"center",justifyContent:"center",fontSize:"1rem",
              boxShadow:`0 2px 8px ${isCorrect?"#5BAD5E":"#D94F3B"}35`,
            }}>{isCorrect?"✅":"❌"}</div>
            <div style={{flex:1}}>
              <div style={{fontSize:".9rem",fontWeight:800,
                color:isCorrect?"#2E7D32":"#C62828",marginBottom:1}}>
                {isCorrect?"Correto!":"Errou!"}
                {isCorrect && score.streak>=3 && <span style={{marginLeft:6,fontSize:".76rem"}}>🔥 {score.streak} seguidas!</span>}
              </div>
              {!isCorrect && (
                <div style={{fontSize:".74rem",color:"#555"}}>
                  A correta é{" "}
                  <span style={{fontFamily:"'Noto Sans JP',sans-serif",fontWeight:900,color:pInfo?.color,fontSize:"1rem"}}>{correctParticle}</span>
                  {" "}— {pInfo?.role}
                </div>
              )}
            </div>
          </div>

          <div style={{padding:"12px 16px",background:"#fff"}}>
            {/* Correct sentence highlighted */}
            <div style={{
              fontFamily:"'Noto Sans JP',sans-serif",
              fontSize:"1.1rem",fontWeight:700,color:"#2D2A26",
              marginBottom:6,lineHeight:1.7,
            }}>
              {cur.parts.map((pt,pi)=>
                pi===cur.slot
                  ? <span key={pi} style={{
                      background:pInfo?.color,color:"#fff",
                      borderRadius:7,padding:"2px 8px",margin:"0 2px",fontWeight:900,
                      boxShadow:`0 2px 6px ${pInfo?.color}40`,
                    }}>{correctParticle}</span>
                  : <span key={pi}>{pt}</span>
              )}
            </div>
            <div style={{fontSize:".74rem",color:"#5A4A3A",fontStyle:"italic",marginBottom:10}}>
              {cur.pt}
            </div>
            {/* Rule card */}
            <div style={{
              display:"flex",gap:10,alignItems:"flex-start",
              background:pInfo?.color+"0a",borderRadius:11,padding:"9px 12px",
              border:`1px solid ${pInfo?.color}20`,marginBottom:12,
            }}>
              <div style={{
                width:26,height:26,borderRadius:7,flexShrink:0,background:pInfo?.color,
                display:"flex",alignItems:"center",justifyContent:"center",
                fontFamily:"'Noto Sans JP',sans-serif",fontSize:".9rem",fontWeight:900,color:"#fff",
              }}>{correctParticle}</div>
              <div style={{flex:1}}>
                <div style={{fontSize:".7rem",fontWeight:700,color:pInfo?.color,marginBottom:2}}>{pInfo?.role}</div>
                <div style={{fontSize:".72rem",color:"#5A4A3A",lineHeight:1.5}}>{pInfo?.tip}</div>
              </div>
            </div>

            <button onClick={next} style={{
              width:"100%",padding:"11px",borderRadius:12,border:"none",
              background:isCorrect?"linear-gradient(135deg,#5BAD5E,#4A9A4D)":"linear-gradient(135deg,#2D2A26,#4A3F30)",
              color:"#fff",fontSize:".88rem",fontWeight:700,fontFamily:"inherit",cursor:"pointer",
              boxShadow:isCorrect?"0 3px 10px rgba(91,173,94,.3)":"0 2px 8px rgba(0,0,0,.15)",
            }}>
              {qIdx+1>=queue.length?"Ver resultado 🏆":"Próxima →"}
            </button>
          </div>
        </div>
      )}
    </div>
  );
});

/* ═══════════════════════════════════════════════════════════════════════════
   N4 TAB COMPONENTS
   ═══════════════════════════════════════════════════════════════════════════ */
function N4LessonDetail({ lesson, speak }) {
  const { lessonId } = lesson.sections[0];
  const DATA = {
    teiru: {
      formula:"[Verbo て] + います / いる", color:"#3A8FD9",
      uses:[
        {icon:"⏳", label:"Ação em progresso",ex:[
          {ja:"にほんごを べんきょうしています。",rom:"Nihongo wo benkyō shite imasu.",pt:"Estou estudando japonês."},
          {ja:"あめが ふっています。",rom:"Ame ga futte imasu.",pt:"Está chovendo."},
          {ja:"ともだちを まっています。",rom:"Tomodachi wo matte imasu.",pt:"Estou esperando um amigo."},
        ]},
        {icon:"💍", label:"Estado resultante",ex:[
          {ja:"かれは けっこんしています。",rom:"Kare wa kekkōn shite imasu.",pt:"Ele é casado."},
          {ja:"にほんに すんでいます。",rom:"Nihon ni sunde imasu.",pt:"Moro no Japão."},
          {ja:"めがねを かけています。",rom:"Megane wo kakete imasu.",pt:"Ele usa óculos."},
        ]},
      ],
      tip:"たべています = está comendo (agora). たべました = comeu (passado simples).",
    },
    tai: {
      formula:"[Raiz do verbo] + たい", color:"#D95CB5",
      conj:[
        {form:"たい",pt:"quero fazer",ex:"いきたい"},
        {form:"たいです",pt:"quero (polido)",ex:"いきたいです"},
        {form:"たくない",pt:"não quero",ex:"いきたくない"},
        {form:"たかった",pt:"queria",ex:"もっと たべたかった"},
      ],
      uses:[
        {icon:"💭", label:"Desejo pessoal",ex:[
          {ja:"にほんごを はなしたいです。",rom:"Nihongo wo hanashitai desu.",pt:"Quero falar japonês."},
          {ja:"あのえいがを みたいです。",rom:"Ano eiga wo mitai desu.",pt:"Quero ver aquele filme."},
          {ja:"なにを たべたいですか？",rom:"Nani wo tabetai desu ka?",pt:"O que você quer comer?"},
        ]},
      ],
      tip:"⚠️ Use たい só para o próprio desejo. Para outros: たがっています (ele parece querer...).",
    },
    potential: {
      formula:"Grupo 2: る→られる | Grupo 1: u→える | する→できる", color:"#5BAD5E",
      table:[
        {dict:"たべる",pot:"たべられる",rom:"taberareru",pt:"poder comer"},
        {dict:"みる",pot:"みられる",rom:"mirareru",pt:"poder ver"},
        {dict:"いく",pot:"いける",rom:"ikeru",pt:"poder ir"},
        {dict:"かく",pot:"かける",rom:"kakeru",pt:"poder escrever"},
        {dict:"はなす",pot:"はなせる",rom:"hanaseru",pt:"poder falar"},
        {dict:"する",pot:"できる",rom:"dekiru",pt:"poder fazer"},
        {dict:"くる",pot:"こられる",rom:"korareru",pt:"poder vir"},
      ],
      uses:[{icon:"💪", label:"Capacidade",ex:[
        {ja:"にほんごが はなせます。",rom:"Nihongo ga hanasemasu.",pt:"Consigo falar japonês."},
        {ja:"ピアノが ひけません。",rom:"Piano ga hikemasen.",pt:"Não sei tocar piano."},
        {ja:"かんじが よめますか？",rom:"Kanji ga yomemasu ka?",pt:"Você sabe ler kanji?"},
      ]}],
      tip:"Na forma potencial, o objeto frequentemente usa が em vez de を。",
    },
    kara_node: {
      formula:"[razão] + から/ので + [resultado]", color:"#E8853A",
      comparison:[
        {marker:"から",style:"Casual / direto",when:"Conversa informal",ex:"つかれたから ねます。",exPt:"Estou cansado, por isso vou dormir."},
        {marker:"ので",style:"Suave / educado",when:"Formal, pedidos",ex:"つかれたので ねます。",exPt:"Como estou cansado, vou dormir."},
      ],
      uses:[{icon:"🔗", label:"Explicando motivo",ex:[
        {ja:"あめだから いきません。",rom:"Ame da kara ikimasen.",pt:"Como está chovendo, não vou."},
        {ja:"びょうきなので やすみます。",rom:"Byōki na node yasumimasu.",pt:"Como estou doente, vou descansar."},
        {ja:"じかんがないので むりです。",rom:"Jikan ga nai node muri desu.",pt:"Como não tenho tempo, é impossível."},
      ]}],
      tip:"ので soa mais educado — implica razão objetiva. から pode soar mais assertivo.",
    },
    nagara: {
      formula:"[Raiz do verbo] + ながら + [ação principal]", color:"#7B5CD9",
      uses:[{icon:"🔀", label:"Ações simultâneas",ex:[
        {ja:"おんがくを ききながら べんきょうします。",rom:"Ongaku wo kikinagara benkyō shimasu.",pt:"Estudo enquanto ouço música."},
        {ja:"あるきながら スマホを みないで。",rom:"Arukinagara sumaho wo minaide.",pt:"Não olhe o celular enquanto caminha."},
        {ja:"テレビを みながら たべます。",rom:"Terebi wo minagara tabemasu.",pt:"Como enquanto assisto TV."},
      ]}],
      tip:"⚠️ Ambas as ações têm o mesmo sujeito. A ação depois de ながら é a principal.",
    },
    kotogaaru: {
      formula:"[Verbo た] + ことが あります", color:"#0891B2",
      uses:[
        {icon:"📖", label:"Experiência de vida",ex:[
          {ja:"にほんに いったことが あります。",rom:"Nihon ni itta koto ga arimasu.",pt:"Já fui ao Japão."},
          {ja:"すしを たべたことが あります。",rom:"Sushi wo tabeta koto ga arimasu.",pt:"Já comi sushi."},
          {ja:"かんじを ならったことが ありません。",rom:"Kanji wo naratta koto ga arimasen.",pt:"Nunca aprendi kanji."},
        ]},
        {icon:"❓", label:"Perguntando sobre experiência",ex:[
          {ja:"にほんに いったことが ありますか？",rom:"Nihon ni itta koto ga arimasu ka?",pt:"Você já foi ao Japão?"},
          {ja:"はじめて にほんりょうりを たべた。",rom:"Hajimete nihon ryōri wo tabeta.",pt:"Comi culinária japonesa pela primeira vez."},
        ]},
      ],
      tip:"いったことがある (já fui) vs いったことがない (nunca fui).",
    },
  };

  const d = DATA[lessonId];
  if (!d) return null;

  return (
    <div style={{display:"flex",flexDirection:"column",gap:10}}>
      <div style={{background:`${d.color}10`,borderRadius:13,padding:"12px 14px",border:`1.5px solid ${d.color}25`}}>
        <div style={{fontSize:".6rem",fontWeight:700,color:"#B0A8A0",textTransform:"uppercase",letterSpacing:".5px",marginBottom:5}}>Estrutura</div>
        <div style={{fontFamily:"'Noto Sans JP',sans-serif",fontSize:".88rem",fontWeight:700,color:d.color}}>{d.formula}</div>
      </div>
      {d.conj && (
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:6}}>
          {d.conj.map((c,i)=>(
            <div key={i} style={{borderRadius:11,padding:"9px 10px",background:d.color+"06",border:`1.5px solid ${d.color}18`}}>
              <div style={{fontFamily:"'Noto Sans JP',sans-serif",fontSize:".9rem",fontWeight:900,color:d.color,marginBottom:2}}>{c.form}</div>
              <div style={{fontSize:".68rem",color:"#5A4A3A"}}>{c.pt}</div>
              <div style={{fontFamily:"'Noto Sans JP',sans-serif",fontSize:".7rem",color:"#B0A8A0",marginTop:2}}>{c.ex}</div>
            </div>
          ))}
        </div>
      )}
      {d.comparison && (
        <div style={{display:"flex",flexDirection:"column",gap:6}}>
          {d.comparison.map((c,i)=>(
            <div key={i} style={{borderRadius:12,overflow:"hidden",border:`1.5px solid ${d.color}25`}}>
              <div style={{padding:"8px 12px",background:d.color+"10",borderBottom:`1px solid ${d.color}15`,display:"flex",alignItems:"center",gap:8}}>
                <span style={{fontFamily:"'Noto Sans JP',sans-serif",fontSize:"1.1rem",fontWeight:900,color:d.color}}>{c.marker}</span>
                <div>
                  <div style={{fontSize:".72rem",fontWeight:700,color:d.color}}>{c.style}</div>
                  <div style={{fontSize:".64rem",color:"#8A8580"}}>{c.when}</div>
                </div>
              </div>
              <div style={{padding:"8px 12px",background:"#fff"}}>
                <div style={{fontFamily:"'Noto Sans JP',sans-serif",fontSize:".9rem",fontWeight:700,color:"#2D2A26",marginBottom:2}}>{c.ex}</div>
                <div style={{fontSize:".72rem",color:"#5A4A3A",fontStyle:"italic"}}>{c.exPt}</div>
              </div>
            </div>
          ))}
        </div>
      )}
      {d.table && (
        <div style={{borderRadius:12,overflow:"hidden",border:`1.5px solid ${d.color}20`}}>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",padding:"7px 10px",background:d.color+"10",borderBottom:`1px solid ${d.color}15`}}>
            {["Dicionário","Potencial","Significado"].map(h=>(
              <div key={h} style={{fontSize:".58rem",fontWeight:700,color:d.color,textTransform:"uppercase"}}>{h}</div>
            ))}
          </div>
          {d.table.map((row,i)=>(
            <div key={i} style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",padding:"8px 10px",background:i%2===0?"#fff":d.color+"04",borderBottom:i<d.table.length-1?`1px solid ${d.color}10`:"none",alignItems:"center"}}>
              <button onClick={()=>speak(row.dict)} style={{fontFamily:"'Noto Sans JP',sans-serif",fontSize:".88rem",fontWeight:700,color:"#2D2A26",background:"none",border:"none",cursor:"pointer",padding:0,textAlign:"left"}}>{row.dict}</button>
              <button onClick={()=>speak(row.pot)} style={{fontFamily:"'Noto Sans JP',sans-serif",fontSize:".88rem",fontWeight:900,color:d.color,background:"none",border:"none",cursor:"pointer",padding:0,textAlign:"left"}}>{row.pot}</button>
              <div style={{fontSize:".64rem",color:"#5A4A3A"}}>{row.pt}</div>
            </div>
          ))}
        </div>
      )}
      {(d.uses||[]).map((u,ui)=>(
        <div key={ui}>
          <div style={{display:"flex",alignItems:"center",gap:6,marginBottom:7}}>
            <span style={{fontSize:".9rem"}}>{u.icon}</span>
            <div style={{fontSize:".78rem",fontWeight:700,color:"#2D2A26"}}>{u.label}</div>
          </div>
          {u.ex.map((ex,ei)=>(
            <div key={ei} style={{borderRadius:11,overflow:"hidden",border:`1.5px solid ${d.color}18`,marginBottom:6}}>
              <div style={{padding:"9px 12px 7px",background:d.color+"07",borderBottom:`1px solid ${d.color}10`,display:"flex",alignItems:"flex-start",justifyContent:"space-between",gap:8}}>
                <div>
                  <div style={{fontFamily:"'Noto Sans JP',sans-serif",fontSize:".96rem",fontWeight:700,color:"#2D2A26",marginBottom:2}}>{ex.ja}</div>
                  <div style={{fontSize:".62rem",color:"#B0A8A0",fontStyle:"italic"}}>{ex.rom}</div>
                </div>
                <button onClick={()=>speak(ex.ja)} style={{background:`${d.color}14`,border:`1px solid ${d.color}25`,borderRadius:7,padding:"4px 9px",cursor:"pointer",fontSize:".76rem",color:d.color,fontFamily:"inherit",flexShrink:0}}>🔊</button>
              </div>
              <div style={{padding:"6px 12px",background:"#fff"}}>
                <span style={{fontSize:".76rem",color:"#5A4A3A",fontWeight:600}}>🇧🇷 {ex.pt}</span>
              </div>
            </div>
          ))}
        </div>
      ))}
      {d.tip && (
        <div style={{display:"flex",gap:8,background:"#FFF8F0",borderRadius:11,padding:"9px 12px",border:`1px solid ${d.color}20`}}>
          <span style={{flexShrink:0}}>💡</span>
          <span style={{fontSize:".76rem",color:"#5A4A3A",lineHeight:1.65}}>{d.tip}</span>
        </div>
      )}
    </div>
  );
}

