                borderRadius:18,overflow:"hidden",
                border:`2px solid ${done?"#FCD34D30":"#E2E8F0"}`,
                background:done?"#FFFBEB":"#fff",
                boxShadow:done
                  ?"0 4px 14px rgba(252,211,77,.2)"
                  :"0 2px 8px rgba(0,0,0,.06)",
                transition:"all .18s",
                display:"flex",flexDirection:"column",
                position:"relative",
