    (Math.min(n4KanjiDone/KANJI_N4.length,1)*34 +
     Math.min(n4VocabDone/ALL_N4_VOCAB.length,1)*33 +
     Math.min(n4GrammarDone/GRAMMAR_LESSONS_N4.length,1)*33)
